test-only helper. I liked the method syntax, and we could still get that
same API with an extension trait—

```diff
@@ -362,6 +356,17 @@ mod tests {
         }
     }
 
+    /// Convenience extension trait to extract the steps from a basin.
+    trait Steps {
+        fn steps(&self) -> Vec<Step>;
+    }
+
+    impl<T> Steps for Basin<T> {
+        fn steps(&self) -> Vec<Step> {
